{"path": "bos_trader.py", "content": "#!/usr/bin/env python3
"""
🤖 BoS_PA Scalping Bot — Binance Futures TESTNET
Strategy: Break of Structure (Price Action) on 15m.
- Entry: close breaks last swing high (LONG) / low (SHORT)
- SL: fixed $1 risk per trade (position sized accordingly)
- TP: SL * RR (1:1 or 1:1.5) via Algo Order API (mandatory on testnet)
- State persisted to bos_trader_state.json (algoIds tracked locally)
SAFE: testnet only, no real funds.
"""
import os, sys, time, hmac, hashlib, json, bisect, signal
import requests

# ===== CONFIG =====
API_KEY = os.getenv('TESTNET_API_KEY')
API_SECRET = os.getenv('TESTNET_API_SECRET')
BASE = 'https://testnet.binancefuture.com'

SYMBOLS = ["SOLUSDT","DOGEUSDT","AVAXUSDT","LINKUSDT","BNBUSDT","XRPUSDT","NEARUSDT",
           "AAVEUSDT","ETCUSDT","RUNEUSDT","LTCUSDT","TRXUSDT","ADAUSDT","DOTUSDT",
           "ATOMUSDT","INJUSDT","SUIUSDT","TIAUSDT","WIFUSDT"]
INTERVAL = "15m"
LEVERAGE = 5
RISK_USD = 1.0          # fixed $1 risk per trade
RR = 1.5                # take profit multiple
SWING = 8               # swing lookback (bars)
POLL_SEC = 60           # check every 60s (candle closes every 900s)
STATE_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), "bos_trader_state.json")

# ===== SIGNING (manual query string — proven to work) =====
def _sign(params):
    q = '&'.join(f'{k}={v}' for k, v in sorted(params.items()))
    return hmac.new(API_SECRET.encode(), q.encode(), hashlib.sha256).hexdigest()

def _req(method, endpoint, params=None, signed=False, timeout=30):
    params = params or {}
    headers = {'X-MBX-APIKEY': API_KEY}
    if signed:
        params['timestamp'] = int(time.time()*1000)
        params['recvWindow'] = 5000
        q = '&'.join(f'{k}={v}' for k, v in sorted(params.items()))
        sig = _sign(params)
        url = f'{BASE}{endpoint}?{q}&signature={sig}'
    else:
        q = '&'.join(f'{k}={v}' for k, v in sorted(params.items()))
        url = f'{BASE}{endpoint}' + (f'?{q}' if q else '')
    r = requests.request(method, url, headers=headers, timeout=timeout)
    try:
        return r.status_code, r.json()
    except Exception:
        return r.status_code, r.text

# ===== EXCHANGE OPS =====
def get_klines(symbol, limit=200):
    code, d = _req('GET', '/fapi/v1/klines', {'symbol':symbol,'interval':INTERVAL,'limit':limit})
    if code != 200: return None
    out = []
    for c in d:
        out.append({'ts':int(c[0]),'open':float(c[1]),'high':float(c[2]),
                    'low':float(c[3]),'close':float(c[4]),'volume':float(c[5])})
    return out

def setup_leverage(symbol):
    _req('POST', '/fapi/v1/leverage', {'symbol':symbol,'leverage':LEVERAGE}, signed=True)

def get_price(symbol):
    code, d = _req('GET', '/fapi/v1/ticker/price', {'symbol':symbol})
    return float(d['price']) if code==200 else None

def get_balance():
    code, d = _req('GET', '/fapi/v2/account', signed=True)
    if code != 200: return None
    return float(d.get('availableBalance', 0))

def place_market(symbol, side, qty):
    params = {'symbol':symbol,'side':side,'type':'MARKET','quantity':f'{qty:.6f}'}
    return _req('POST', '/fapi/v1/order', params, signed=True)

def place_algo_sl_tp(symbol, side, qty, sl_price, tp_price):
    """Place SL & TP via Algo Order API (mandatory on testnet since Dec 2025)."""
    ids = []
    # SL (STOP_MARKET)
    sl_side = 'SELL' if side=='BUY' else 'BUY'
    p = {'symbol':symbol,'algoType':'CONDITIONAL','type':'STOP_MARKET',
         'side':sl_side,'quantity':f'{qty:.6f}',
         'triggerPrice':f'{sl_price:.6f}','workingType':'MARK_PRICE'}
    code, d = _req('POST', '/fapi/v1/algoOrder', p, signed=True)
    if code == 200 and 'algoId' in d:
        ids.append(d['algoId'])
    else:
        print(f"  ⚠️ SL algo failed {symbol}: {code} {d}")
    # TP (TAKE_PROFIT_MARKET)
    p2 = {'symbol':symbol,'algoType':'CONDITIONAL','type':'TAKE_PROFIT_MARKET',
          'side':sl_side,'quantity':f'{qty:.6f}',
          'triggerPrice':f'{tp_price:.6f}','workingType':'MARK_PRICE'}
    code2, d2 = _req('POST', '/fapi/v1/algoOrder', p2, signed=True)
    if code2 == 200 and 'algoId' in d2:
        ids.append(d2['algoId'])
    else:
        print(f"  ⚠️ TP algo failed {symbol}: {code2} {d2}")
    return ids

def cancel_algo(symbol, algo_id):
    return _req('DELETE', '/fapi/v1/algoOrder', {'symbol':symbol,'algoId':str(algo_id)}, signed=True)

def has_position(symbol):
    code, d = _req('GET', '/fapi/v2/positionRisk', signed=True)
    if code != 200: return False
    for p in d:
        if p['symbol']==symbol and abs(float(p['positionAmt']))>1e-6:
            return True
    return False

# ===== STRATEGY (BoS_PA) =====
def detect_swings(candles, n=SWING):
    hi=[c['high'] for c in candles]; lo=[c['low'] for c in candles]
    sh=[]; sl=[]
    for i in range(n, len(candles)-n):
        win_h=hi[i-n:i+n+1]; win_l=lo[i-n:i+n+1]
        if hi[i]==max(win_h): sh.append(i)
        if lo[i]==min(win_l): sl.append(i)
    return sh, sl

def bos_signal(candles, sh, sl):
    n=len(candles)
    if n < SWING*2: return 0
    i=n-2  # penultimate candle (last is forming)
    c=candles[i]['close']
    jh=bisect.bisect_left(sh,i); jl=bisect.bisect_left(sl,i)
    if jh>0 and c>candles[sh[jh-1]]['high']: return 1
    if jl>0 and c<candles[sl[jl-1]]['low']: return -1
    return 0

# ===== STATE =====
def load_state():
    if os.path.exists(STATE_FILE):
        try: return json.load(open(STATE_FILE))
        except: pass
    return {'positions':{}, 'algo_ids':{}}

def save_state(st):
    json.dump(st, open(STATE_FILE,'w'), indent=2)

# ===== MAIN LOOP =====
_running=True
def _sig(s,f):
    global _running; _running=False

def main():
    global _running
    signal.signal(signal.SIGINT,_sig); signal.signal(signal.SIGTERM,_sig)
    if not API_KEY or not API_SECRET:
        print("❌ TESTNET_API_KEY/SECRET not set"); return 1
    print("="*60); print("🤖 BoS_PA Testnet Bot | SYM=%d | RR=1:%.1f | Risk=$%.0f"%(len(SYMBOLS),RR,RISK_USD))
    print("="*60)
    for s in SYMBOLS:
        try: setup_leverage(s)
        except: pass
    st=load_state()
    bal0=get_balance()
    print(f"💰 Balance: ${bal0:.2f}" if bal0 else "💰 Balance: n/a")
    print("🚀 Loop started (Ctrl+C to stop)\n")
    last_ts={}
    while _running:
        try:
            for sym in SYMBOLS:
                if sym in st['positions']:  # already in trade, skip
                    continue
                kl=get_klines(sym, 200)
                if not kl: continue
                sh,sl=detect_swings(kl)
                sig=bos_signal(kl, sh, sl)
                if sig==0: continue
                price=get_price(sym)
                if not price: continue
                # SL distance = 0.2% of price (from backtest)
                sl_dist=max(price*0.002, 1e-6)
                sl_price=price-sl_dist if sig==1 else price+sl_dist
                tp_price=price+sl_dist*RR if sig==1 else price-sl_dist*RR
                side='BUY' if sig==1 else 'SELL'
                # position size: risk $1 / sl_dist_price
                qty=RISK_USD/sl_dist
                # round to symbol precision (use min notional guard)
                code,d=place_market(sym, side, qty)
                if code==200 and 'orderId' in d:
                    aids=place_algo_sl_tp(sym, side, qty, sl_price, tp_price)
                    st['positions'][sym]={'side':side,'entry':price,'sl':sl_price,'tp':tp_price,'qty':qty,'algo':aids,'t':int(time.time())}
                    st['algo_ids'][sym]=aids
                    save_state(st)
                    print(f"  ✅ {sym} {side} @ {price:.4f} | SL={sl_price:.4f} TP={tp_price:.4f} qty={qty:.2f} algo={aids}")
                else:
                    print(f"  ❌ {sym} order failed: {code} {str(d)[:120]}")
            # prune closed positions
            for sym in list(st['positions'].keys()):
                if not has_position(sym):
                    # cancel leftover algos
                    for aid in st['algo_ids'].get(sym,[]):
                        try: cancel_algo(sym, aid)
                        except: pass
                    del st['positions'][sym]
                    st['algo_ids'].pop(sym, None)
                    save_state(st)
                    print(f"  🔄 {sym} closed -> state cleared")
            time.sleep(POLL_SEC)
        except KeyboardInterrupt:
            _running=False; break
        except Exception as e:
            print(f"  ❌ Loop err: {e}"); time.sleep(5)
    # shutdown: cancel all algos
    print("\n🛑 Shutdown — cancelling algo orders...")
    for sym,aids in st['algo_ids'].items():
        for aid in aids:
            try: cancel_algo(sym,aid)
            except: pass
    print("✅ Done")

if __name__=='__main__':
    sys.exit(main() or 0)
"}

